const upsertProviderCursor = `-- name: UpsertProviderCursor :execrows
INSERT INTO payment_provider_cursor (
    workspace_id,
    provider_code,
    network,
    source_key,
    cursor_value,
    cursor_sequence
)
VALUES (?, ?, ?, ?, ?, ?)
ON DUPLICATE KEY UPDATE
    cursor_value = IF(
        VALUES(cursor_sequence) >= cursor_sequence,
        VALUES(cursor_value),
        cursor_value
    ),
    cursor_sequence = GREATEST(cursor_sequence, VALUES(cursor_sequence)),
    updated_at = NOW()
`

type UpsertProviderCursorParams struct {
	WorkspaceID    string `json:"workspace_id"`
	ProviderCode   string `json:"provider_code"`
	Network        string `json:"network"`
	SourceKey      string `json:"source_key"`
	CursorValue    string `json:"cursor_value"`
	CursorSequence uint64 `json:"cursor_sequence"`
}

func (q *Queries) UpsertProviderCursor(ctx context.Context, arg UpsertProviderCursorParams) (int64, error) {
	result, err := q.exec(ctx, q.upsertProviderCursorStmt, upsertProviderCursor,
		arg.WorkspaceID,
		arg.ProviderCode,
		arg.Network,
		arg.SourceKey,
		arg.CursorValue,
		arg.CursorSequence,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}
